# Prompt: Build a function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_file(filename):
    try:
        path = f"uploads/{filename}"
        if os.path.exists(path):
            os.remove(path)
            print(f"File {filename} has been deleted successfully.")
        else:
            print(f"File {filename} not found in uploads directory.")
    except Exception as e:
        print(f"An error occurred: {e}")